"use client"

import * as React from "react"
import {
  PageHeader,
  StatGroup,
  LoyaltySummaryCard,
  FilterChips,
  type FilterChip,
  ListCard,
  Badge,
  Tag,
  Checkbox,
  Button,
  BottomActionBar,
  EmptyState,
  Separator,
  Rating,
  formatCurrency,
} from "@gunjo/ui"
import {
  IconReceipt,
  IconMapPin,
  IconCreditCard,
  IconCircleCheck,
  IconBriefcase,
  IconDownload,
  IconX,
  IconArrowNarrowRight,
  IconSearch,
} from "@tabler/icons-react"
import {
  RIDES,
  SUMMARY,
  PAY_LABEL,
  groupByMonth,
  type Ride,
  type PayMethod,
} from "./data"
import { ReceiptSheet } from "./ReceiptSheet"

const yen = (n: number) => formatCurrency(n, { currency: "JPY" })

type PeriodFilter = "all" | "2026-06" | "2026-05"

const PERIOD_CHIPS: FilterChip[] = [
  { value: "all", label: "すべて" },
  { value: "2026-06", label: "今月" },
  { value: "2026-05", label: "先月" },
]

type PayFilter = "all" | PayMethod
const PAY_CHIPS: FilterChip[] = [
  { value: "all", label: "支払い: すべて" },
  { value: "credit", label: "クレジット" },
  { value: "app", label: "アプリ決済" },
  { value: "dpay", label: "d払い" },
  { value: "cash", label: "現金" },
]

export default function TaxiHistoryPage() {
  const [period, setPeriod] = React.useState<PeriodFilter>("all")
  const [pay, setPay] = React.useState<PayFilter>("all")
  const [expenseOnly, setExpenseOnly] = React.useState(false)

  // 選択モード（経費まとめてダウンロード）
  const [selectMode, setSelectMode] = React.useState(false)
  const [selected, setSelected] = React.useState<Set<string>>(new Set())

  // 領収書シート
  const [openRide, setOpenRide] = React.useState<Ride | null>(null)
  const [receiptOpen, setReceiptOpen] = React.useState(false)
  const [addressee, setAddressee] = React.useState("株式会社グンジョー")

  const filtered = React.useMemo(() => {
    return RIDES.filter((r) => {
      if (period !== "all" && !r.datetime.startsWith(period)) return false
      if (pay !== "all" && r.pay !== pay) return false
      if (expenseOnly && !r.expenseTag) return false
      return true
    })
  }, [period, pay, expenseOnly])

  const groups = React.useMemo(() => groupByMonth(filtered), [filtered])

  const toggleSelect = (id: string) => {
    setSelected((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  const exitSelectMode = () => {
    setSelectMode(false)
    setSelected(new Set())
  }

  const openReceipt = (ride: Ride) => {
    setOpenRide(ride)
    setReceiptOpen(true)
  }

  const selectedRides = filtered.filter((r) => selected.has(r.id))
  const selectedTotal = selectedRides.reduce((s, r) => s + r.fare, 0)

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-muted/30">
      <PageHeader
        title="乗車履歴"
        subtitle="渋谷きずなタクシー"
        actions={
          selectMode ? (
            <Button variant="ghost" size="sm" onClick={exitSelectMode}>
              <IconX className="size-4" aria-hidden="true" />
              選択を解除
            </Button>
          ) : (
            <Button variant="ghost" size="sm" onClick={() => setSelectMode(true)}>
              <IconBriefcase className="size-4" aria-hidden="true" />
              経費精算
            </Button>
          )
        }
      />

      <main className="flex-1 space-y-4 px-3 py-4 pb-28">
        {/* 利用サマリ */}
        {!selectMode && (
          <section aria-label="利用サマリ" className="space-y-3">
            <LoyaltySummaryCard
              tone="brand"
              balanceLabel="保有ポイント"
              balance={SUMMARY.pointsBalance.toLocaleString("ja-JP")}
              unit="P"
              tier={SUMMARY.tier}
              meta="渋谷きずなタクシー アプリ"
              secondary={[{ label: "今月の獲得", value: `+${SUMMARY.pointsEarned} P` }]}
              progress={{
                value: SUMMARY.pointsBalance,
                max: SUMMARY.pointsBalance + SUMMARY.pointsToNextTier,
                label: `${SUMMARY.nextTier}まであと ${SUMMARY.pointsToNextTier} P`,
              }}
            />
            <StatGroup
              cols={3}
              items={[
                { label: `${SUMMARY.monthLabel}の利用`, value: `${SUMMARY.count}回` },
                { label: "利用金額", value: yen(SUMMARY.total) },
                { label: "獲得ポイント", value: `${SUMMARY.pointsEarned}P`, tone: "positive" },
              ]}
            />
          </section>
        )}

        {/* 絞り込み */}
        <section aria-label="絞り込み" className="space-y-2">
          <FilterChips
            aria-label="期間で絞り込み"
            items={PERIOD_CHIPS}
            value={period}
            onValueChange={(v) => setPeriod(v as PeriodFilter)}
          />
          <FilterChips
            aria-label="支払い方法で絞り込み"
            items={PAY_CHIPS}
            value={pay}
            onValueChange={(v) => setPay(v as PayFilter)}
          />
          <div className="px-1">
            <Checkbox
              checked={expenseOnly}
              onCheckedChange={setExpenseOnly}
              label="経費タグ付きのみ表示"
            />
          </div>
        </section>

        {/* 乗車履歴の一覧（月別グルーピング） */}
        {groups.length === 0 ? (
          <EmptyState
            icon={<IconSearch className="size-8" aria-hidden="true" />}
            title="該当する乗車履歴がありません"
            description="絞り込み条件を変更してください。"
            action={
              <Button
                variant="outline"
                size="sm"
                onClick={() => {
                  setPeriod("all")
                  setPay("all")
                  setExpenseOnly(false)
                }}
              >
                絞り込みをリセット
              </Button>
            }
          />
        ) : (
          groups.map((group) => (
            <section key={group.key} aria-label={`${group.label}の乗車履歴`} className="space-y-2">
              {/* 月見出し（履歴のグループヘッダ） */}
              <div className="flex items-baseline justify-between px-1">
                <h2 className="text-sm font-semibold text-foreground">{group.label}</h2>
                <p className="text-xs tabular-nums text-muted-foreground">
                  {group.count}回・{yen(group.total)}
                </p>
              </div>

              <div className="space-y-2">
                {group.rides.map((ride) => (
                  <ListCard
                    key={ride.id}
                    selected={selectMode && selected.has(ride.id)}
                    onSelect={() => (selectMode ? toggleSelect(ride.id) : openReceipt(ride))}
                    leading={
                      selectMode ? (
                        <Checkbox
                          checked={selected.has(ride.id)}
                          onCheckedChange={() => toggleSelect(ride.id)}
                          aria-label={`${ride.dateLabel} ${ride.from}から${ride.to}を選択`}
                        />
                      ) : (
                        <span className="flex size-9 items-center justify-center rounded-full bg-muted text-muted-foreground">
                          <IconMapPin className="size-5" aria-hidden="true" />
                        </span>
                      )
                    }
                    trailing={
                      selectMode ? null : (
                        <div className="flex flex-col items-end gap-0.5">
                          <span className="whitespace-nowrap text-base font-semibold tabular-nums text-foreground">
                            {yen(ride.fare)}
                          </span>
                          {ride.receiptIssued ? (
                            <span className="flex items-center gap-0.5 text-[11px] text-success">
                              <IconCircleCheck className="size-3.5" aria-hidden="true" />
                              領収書発行済
                            </span>
                          ) : (
                            <span className="text-[11px] text-warning">領収書 未発行</span>
                          )}
                        </div>
                      )
                    }
                    title={
                      <span className="flex items-center gap-1.5 text-sm">
                        <span className="truncate font-medium">{ride.from}</span>
                        <IconArrowNarrowRight className="size-4 shrink-0 text-muted-foreground" aria-hidden="true" />
                        <span className="truncate font-medium">{ride.to}</span>
                      </span>
                    }
                    description={
                      <span className="flex flex-wrap items-center gap-x-2 gap-y-0.5 text-xs text-muted-foreground">
                        <span className="tabular-nums">{ride.dateLabel}</span>
                        <span aria-hidden="true">·</span>
                        <span className="inline-flex items-center gap-0.5">
                          <IconCreditCard className="size-3.5" aria-hidden="true" />
                          {PAY_LABEL[ride.pay]}
                        </span>
                        <span aria-hidden="true">·</span>
                        <span className="tabular-nums">{ride.distanceKm}km</span>
                      </span>
                    }
                    tags={
                      <span className="flex flex-wrap items-center gap-1.5">
                        {ride.expenseTag && (
                          <Tag variant="outline" size="sm">
                            <IconBriefcase className="size-3" aria-hidden="true" />
                            {ride.expenseTag}
                          </Tag>
                        )}
                        {selectMode && ride.points > 0 && (
                          <Tag size="sm">+{ride.points}P</Tag>
                        )}
                        {!selectMode && typeof ride.rating === "number" && (
                          <Rating value={ride.rating} size="sm" label={`ドライバー評価 ${ride.rating}点`} />
                        )}
                      </span>
                    }
                  />
                ))}
              </div>
            </section>
          ))
        )}

        {!selectMode && groups.length > 0 && (
          <>
            <Separator className="my-2" />
            <p className="px-1 text-center text-xs text-muted-foreground">
              履歴は過去24か月分まで表示されます
            </p>
          </>
        )}
      </main>

      {/* 経費まとめてダウンロード（選択モード時の常駐バー） */}
      {selectMode && (
        <BottomActionBar
          sticky
          maxWidth="md"
          actions={
            <Button
              variant="primary"
              size="lg"
              disabled={selected.size === 0}
              onClick={() => {
                // 本番では選択した領収書を ZIP/PDF でまとめて生成。
                exitSelectMode()
              }}
            >
              <IconDownload className="size-5" aria-hidden="true" />
              まとめてダウンロード
            </Button>
          }
        >
          <div className="flex flex-col">
            <span className="text-sm font-semibold text-foreground">
              選択中 {selected.size}件
            </span>
            <span className="text-xs tabular-nums text-muted-foreground">
              合計 {yen(selectedTotal)}
            </span>
          </div>
        </BottomActionBar>
      )}

      {/* 領収書の詳細・発行 */}
      <ReceiptSheet
        ride={openRide}
        open={receiptOpen}
        onOpenChange={setReceiptOpen}
        addressee={addressee}
        onAddresseeChange={setAddressee}
      />
    </div>
  )
}

// Mock 乗車履歴 data for the 渋谷きずなタクシー consumer app.
// Pure data only (no functions) so it can be imported from server or client safely.

export type PayMethod = "credit" | "dpay" | "app" | "cash"

export interface FareLine {
  /** 表示ラベル（運賃 / 迎車料金 / 高速代 / 深夜割増 / アプリ割引 など） */
  label: string
  /** 金額（円）。割引・控除はこの値を正で入れて kind: "subtract" にする */
  amount: number
  kind: "add" | "subtract"
  note?: string
}

export interface Ride {
  id: string
  /** ISO 乗車日時 */
  datetime: string
  /** 表示用：6月24日(火) 21:42 */
  dateLabel: string
  from: string
  to: string
  /** 合計運賃（円） */
  fare: number
  pay: PayMethod
  /** 領収書の発行状態 */
  receiptIssued: boolean
  /** 領収書番号（発行済みのみ） */
  receiptNo?: string
  /** 経費タグ（プロジェクト / 法人）。未設定なら undefined */
  expenseTag?: string
  /** ドライバー評価（5段階）。未評価なら undefined */
  rating?: number
  /** 走行距離 / 所要時間など */
  distanceKm: number
  durationMin: number
  /** 獲得ポイント */
  points: number
  /** 運賃内訳 */
  fareLines: FareLine[]
  /** 領収書の但し書き */
  proviso: string
}

export interface MonthGroup {
  /** "2026-06" */
  key: string
  /** "2026年6月" */
  label: string
  rides: Ride[]
  /** その月の利用回数 */
  count: number
  /** その月の利用金額合計 */
  total: number
}

