/** 月でグルーピング（新しい月が先頭）。data の rides 順を尊重。 */
export function groupByMonth(rides: Ride[]): MonthGroup[] {
  const map = new Map<string, Ride[]>()
  for (const r of rides) {
    const key = r.datetime.slice(0, 7) // YYYY-MM
    const arr = map.get(key)
    if (arr) arr.push(r)
    else map.set(key, [r])
  }
  return Array.from(map.entries()).map(([key, rs]) => {
    const [y, m] = key.split("-")
    return {
      key,
      label: `${Number(y)}年${Number(m)}月`,
      rides: rs,
      count: rs.length,
      total: rs.reduce((s, r) => s + r.fare, 0),
    }
  })
}
